        const autoAdvanceAfterSubmit = overrideAutoAdvance != null
            ? overrideAutoAdvance
            : (configAutoAdvance != null
                ? configAutoAdvance
                : (storedAutoAdvance != null ? storedAutoAdvance : fallbackAutoAdvance));

